var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이 숲은 옛날 그대로네.","JPN":"この森は昔のままね。","ENG":"This forest looks just like it used to.","TWN":"這片樹林還是老樣子呢。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"기억나. 어릴 때는 다른 아이들과 놀러 다니면서 여기저기에 별명을 붙여 주곤 했지.","JPN":"思い出すわ。子供の頃は他の子たちと一緒に遊びながら、色んな場所に名前を付けたっけ。","ENG":"I remember. I would run around the forest with other kids, and give nicknames to everything.","TWN":"我記得，小時候和其他小朋友一起玩耍時，還給它們一個個取了名字。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이 바위는 뾰족해서 송곳 바위, 저 나무는 휘어져 있어서 할머니 나무. 그리고......","JPN":"この岩は尖ってるから「とんがり岩」、あの木は曲がってるから「おばあちゃんの木」。それから……","ENG":"This pointy rock was called the Ice Pick, and that bent tree, the Grandma Tree. And...","TWN":"這塊石頭很尖，所以叫錐子石，那棵樹是彎的，所以叫老奶奶樹，還有……"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......학회의 상징. ","JPN":"……学会の象徴。 ","ENG":"The symbol of the Society. ","TWN":"……學會的象徵。"},"stage":{"bg":"SS_ESPR_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"요즘도 이런 걸 걸어 놓는구나.","JPN":"今でもこんなものを掛けておくのね。","ENG":"I'm surprised they're still hanging this thing.","TWN":"現在也掛著這種東西啊。"},"stage":{"bg":"SS_ESPR_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"뭐, 앞으로는 더 볼 일 없겠지만.","JPN":"まあ、もう二度と目にすることは無いでしょうけれど。","ENG":"Well, I guess this will be the last time I see it again.","TWN":"嗯，雖然以後應該再也看不到了。"},"stage":{"bg":"SS_ESPR_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SS_ESPR_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그런데...... 좀 이상하네.","JPN":"でも……何だかおかしいわね。","ENG":"But it's strange.","TWN":"不過……有些奇怪呢。"},"stage":{"bg":"SS_ESPR_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"옛날에도 이렇게 기분 나쁘게 생겼었나......?","JPN":"昔からこんなに不気味だったかしら……？","ENG":"Did it look this creepy back in the day?","TWN":"這以前看起來有這麼不舒服嗎……？"},"stage":{"bg":"SS_ESPR_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"NEVI_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>지역 정보를 확인할 수 없습니다. 단말기를 초기화한 뒤 다시 시도해 주십시오.</color>","JPN":"<color=#ffd34c>地域情報を確認できません。端末を初期化してからもう一度ご確認ください。</color>","ENG":"<color=#ffd34c>Location check failed. Please reset your device and try again.</color>","TWN":"<color=#ffd34c>無法確認地區情報。請將裝置初始化後重新嘗試。</color>"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"뭐야. 최신형이라고 해서 샀더니.","JPN":"おかしいわね、最新型だって言うから買ったのに。","ENG":"Huh? This is supposed to be the latest model.","TWN":"什麼啊，聽說這是最新型號所以才買的。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"벌써 고장일 리는 없고...... 촌구석이라 통신 상태가 안 좋나?","JPN":"こんなに早く壊れるはずはないし……田舎だから通信状態が悪いのかしら？","ENG":"Is it broken already? Maybe the reception is bad, being so far away from the city.","TWN":"不可能這就出故障了吧……是因為太偏僻了，所以信號才不好的嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......응? 또 걸려 있잖아?","JPN":"……あら？　また掛けてある……","ENG":"Huh? There's the symbol again.","TWN":"……嗯？又中斷了？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"희한하네. 흠집이 난 곳까지 처음 봤던 거랑 똑같이 생겼어.","JPN":"変ね。傷のある場所まで、さっき見たのと全く同じだわ。","ENG":"That's odd. This symbol looks just like the one I saw before, even the scratches on it.","TWN":"奇怪了，連有痕跡的地方都和第一次看到的一模一樣。"},"stage":{"bg":"SS_ESPR_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그러고 보니...... 주변 풍경도 비슷하네.","JPN":"そういえば……周りの風景もよく似てる。","ENG":"And now that I think of it, all my surroundings look the same.","TWN":"這麼說來……周圍的風景也很像。"},"stage":{"bg":"SS_ESPR_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"설마...... 같은 자리로 돌아온 건 아니겠지?","JPN":"まさか……同じ場所に戻って来たわけではないわよね？","ENG":"No, I'm not walking in circles now, am I?","TWN":"該不會……是回到同樣的地方了？"},"stage":{"bg":"SS_ESPR_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......후훗. 나도 참. 남들이 들으면 웃을 소리나 하고.","JPN":"……ふふっ、私ったら。人に聞かれたら笑われちゃうわ。","ENG":"Heh. Listen to yourself, Regina. It's lucky that no one was around to hear that.","TWN":"……呵呵，我還真是，被別人聽見了會被嘲笑吧。"},"stage":{"bg":"SS_ESPR_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"숲은 어딜 가나 비슷해 보이니까. 먼 길을 오느라 피곤해진 거겠지.","JPN":"森はどこでも同じように見えるものだし。長旅に疲れたせいね。","ENG":"Everything looks the same when I'm in a forest. I must be tired from the long journey.","TWN":"因為在樹林中，景色無論在哪裡都很像，而且走了這麼遠，應該是我累了吧。"},"stage":{"bg":"SS_ESPR_02","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};